### Instruction:
The existing endpoint, app.post("/data/csv"), is designed to read a CSV file from an FTP server and send it back in a particular format. However, the functionality needs to be expanded. Your task is to develop an equivalent endpoint, /data/img, that retrieves an image corresponding to the file in the FTP and returns it as a string data URL. The endpoint should include a new parsing method that is capable of handling the image data, as well as any necessary modifications to the existing FTP connection code. Note that the new endpoint should still adhere to the existing server framework and be able to handle all input/output data types.

### Response:
To retrieve an image corresponding to the file in the FTP, we can use the `ftp.get()` method to download the file from the FTP server. Then, we can use the `fs.readFileSync()` method to read the contents of the file and encode it as a string data URL using the `Buffer` class. Finally, we can send the encoded image as the response using the `res.send()` method.

Here's an example implementation for the `/data/img` endpoint:

```javascript
const ftp = require('basic-ftp');
const express = require('express');
const fs = require('fs');

const app = express();

app.get('/data/img', async (req, res) => {
  try {
    const client = new ftp.Client();
    await client.access({
      host: 'ftp.example.com',
      user: 'username',
      password: 'password',
    });
    const stream = await client.download('/path/to/image.png');
    const buffer = await streamToBuffer(stream);
    const dataUrl = encodeDataUrl(buffer, 'image/png');
    res.send(dataUrl);
  } catch (err) {
    console.error(err);
    res.sendStatus(500);
  }
});

async function streamToBuffer(stream) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    stream.on('data', (chunk) => chunks.push(chunk));
    stream.on('end', () => resolve(Buffer.concat(chunks)));
    stream.on('error', reject);
  });
}

function encodeDataUrl(buffer, type) {
  return `data:${type};base64,${buffer.toString('base64')}`;
}
```

Note that this implementation assumes that the FTP server is hosted on `ftp.example.com` and that the image file is located at `/path/to/image.png`. You'll need to modify the code accordingly to match your specific use case.

